 18→void ULFPHealthBarWidget::BindToUnit(ALFPTacticsUnit* Unit)
 19→{
 20→	if (!Unit || BoundUnit == Unit) return;
 21→
 22→	// 解绑旧单位
 23→	UnbindFromUnit();
 24→
 25→	// 绑定新单位
 26→	BoundUnit = Unit;
 27→
 28→	// 订阅事件
 29→	BoundUnit->OnHealthChangedDelegate.AddDynamic(this, &ULFPHealthBarWidget::OnHealthChanged);
 30→	BoundUnit->OnDeathDelegate.AddDynamic(this, &ULFPHealthBarWidget::OnUnitDeath);
 31→
 32→	// 初始化数据
 33→	UpdateHealthBar(BoundUnit->GetCurrentHealth(), BoundUnit->GetMaxHealth());
 34→
 35→	// 显示血条
 36→	SetVisibility(ESlateVisibility::Visible);
 37→
 38→	// 更新阵营颜色
 39→	if (BoundUnit)
 40→	{
 41→		UpdateAffiliationColor(BoundUnit->GetAffiliation());
 42→	}
 43→}
 44→
 45→void ULFPHealthBarWidget::UnbindFromUnit()
 46→{
 47→	if (BoundUnit)
 48→	{
 49→		// 取消订阅事件
 50→		BoundUnit->OnHealthChangedDelegate.RemoveDynamic(this, &ULFPHealthBarWidget::OnHealthChanged);
 51→		BoundUnit->OnDeathDelegate.RemoveDynamic(this, &ULFPHealthBarWidget::OnUnitDeath);
 52→		BoundUnit = nullptr;
 53→	}
 54→
 55→	// 隐藏血条
 56→	SetVisibility(ESlateVisibility::Hidden);
 57→}
