 59→void ULFPHealthBarWidget::UpdateHealthBar(int32 CurrentHealth, int32 MaxHealth)
 60→{
 61→	if (!HealthProgressBar || !HealthText) return;
 62→
 63→	// 计算血量百分比
 64→	float HealthPercent = (MaxHealth > 0) ? (float)CurrentHealth / MaxHealth : 0.0f;
 65→
 66→	// 更新进度条
 67→	HealthProgressBar->SetPercent(HealthPercent);
 68→
 69→	// 更新文本
 70→	FString HealthString = FString::Printf(TEXT("%d / %d"), CurrentHealth, MaxHealth);
 71→	HealthText->SetText(FText::FromString(HealthString));
 72→}
 73→
 74→void ULFPHealthBarWidget::OnHealthChanged(int32 CurrentHealth, int32 MaxHealth)
 75→{
 76→	UpdateHealthBar(CurrentHealth, MaxHealth);
 77→}
