 79→void ULFPHealthBarWidget::OnUnitDeath()
 80→{
 81→	// 单位死亡时隐藏血条
 82→	SetVisibility(ESlateVisibility::Hidden);
 83→
 84→	// 可选：显示死亡效果或文本
 85→	if (HealthText)
 86→	{
 87→		HealthText->SetText(FText::FromString(TEXT("DEAD")));
 88→	}
