 59→void ALFPTacticsUnit::BeginPlay()
 60→{
 61→    Super::BeginPlay();
 62→
 63→    // 注册到回合管理器
 64→    if (ALFPTurnManager* TurnManager = GetTurnManager())
 65→    {
 66→        TurnManager->RegisterUnit(this);
 67→    }
 68→
 69→    for (ULFPBetrayalCondition* Condition : BetrayalConditions)
 70→    {
 71→        if (Condition)
 72→        {
 73→            Condition->RegisterCondition(this);
 74→        }
 75→    }
 76→
 77→    FLFPHexCoordinates SpawnPoint = FLFPHexCoordinates(StartCoordinates_Q, StartCoordinates_R);
 78→    SetCurrentCoordinates(SpawnPoint);
 79→
 80→	// 初始化血量
 81→    CurrentHealth = MaxHealth;
 82→	InitializeHealthBar();
 83→
 84→    PlannedSkillIconComponent->SetRelativeLocation(FVector(0, SkillIconTopDist, 0)); // 在血条上方
 85→
 86→    // 如果是敌方单位，创建AI控制器
 87→    if (IsEnemy())
 88→    {
 89→        FActorSpawnParameters SpawnParams;
 90→        SpawnParams.Owner = this;
 91→        SpawnParams.SpawnCollisionHandlingOverride = ESpawnActorCollisionHandlingMethod::AlwaysSpawn;
 92→
 93→        if (AIControllerClass)
 94→        {
 95→            AIController = GetWorld()->SpawnActor<ALFPAIController>(AIControllerClass, SpawnParams);
 96→            if (AIController)
 97→            {
 98→                AIController->Possess(this);
 99→                AIController->SetControlledUnit(this);
100→            }
101→        }
102→    }
103→}
