123→void ALFPTacticsUnit::SetCurrentCoordinates(const FLFPHexCoordinates& NewCoords)
124→{
125→    // 清除旧位置
126→    if (ALFPHexGridManager* GridManager = GetGridManager())
127→    {
128→        if (ALFPHexTile* LastTile = GridManager->GetTileAtCoordinates(CurrentCoordinates))
129→        {
130→            LastTile->SetIsOccupied(false);
131→            LastTile->SetUnitOnTile(nullptr);
132→        }
133→        if (ALFPHexTile* Tile = GridManager->GetTileAtCoordinates(NewCoords))
134→        {
135→            SetActorLocation(Tile->GetActorLocation() + FVector(0, 0, 1));
136→            Tile->SetIsOccupied(true);
137→            Tile->SetUnitOnTile(this);
138→            CurrentCoordinates = NewCoords;
139→        }
140→    }
141→}
