437→void ALFPTacticsUnit::TakeDamage(int32 Damage)
438→{
439→    if (bIsDead) return;
440→
441→	// 计算实际伤害（考虑防御）
442→	int32 ActualDamage = FMath::Max(Damage - Defense, 1);
443→	int32 OldHealth = CurrentHealth;
444→	CurrentHealth = FMath::Max(CurrentHealth - ActualDamage, 0);
445→
446→	// 广播血量变化事件
447→	OnHealthChangedDelegate.Broadcast(CurrentHealth, MaxHealth);
448→
449→	// 蓝图事件
450→	OnTakeDamage(ActualDamage);
451→
452→	// 检查死亡
453→	if (CurrentHealth <= 0)
454→	{
455→		HandleDeath();
456→	}
457→}
