459→void ALFPTacticsUnit::Heal(int32 Amount)
460→{
461→	if (bIsDead) return;
462→
463→	int32 OldHealth = CurrentHealth;
464→	CurrentHealth = FMath::Min(CurrentHealth + Amount, MaxHealth);
465→
466→	// 广播血量变化事件
467→	OnHealthChangedDelegate.Broadcast(CurrentHealth, MaxHealth);
468→
469→	// 蓝图事件
470→	OnHeal(Amount);
471→}
