 41→{
 42→    if (!Unit || !PC || !SkillGrid) return;
 43→
 44→    OwnerUnit = Unit;
 45→    TacticsPC = PC;
 46→
 47→    // 绑定阵营 AP 变化委托（先移除旧绑定，避免重复添加触发断言）
