 81→void ALFPTurnManager::BeginNewRound()
 82→{
 83→    if (bBattleEnded) return;
 84→
 85→    CurrentRound++;
 86→    bIsInRound = true;
 87→
 88→    // 重置所有单位
 89→    for (ALFPTacticsUnit* Unit : TurnOrderUnits)
 90→    {
 91→        if (Unit && Unit->IsValidLowLevel())
 92→        {
 93→            Unit->ResetForNewRound();
 94→        }
 95→    }
 96→
 97→    // 按速度排序单位
 98→    SortUnitsBySpeed();
 99→
100→    // 清空上一轮的敌人计划
101→    EnemyActionPlans.Empty();
102→    AllocatedSkills.Empty();
103→
104→    // 恢复阵营 AP
105→    for (auto& Pair : FactionCurrentAP)
106→    {
107→        Pair.Value = FMath::Min(Pair.Value + FactionAPRecovery, FactionMaxAP);
108→        OnFactionAPChanged.Broadcast(Pair.Key, Pair.Value);
109→    }
110→
111→    // 进入敌人规划阶段
112→    BeginEnemyPlanningPhase();
113→}
114→
115→void ALFPTurnManager::EndCurrentRound()
116→{
117→    if (bBattleEnded) return;
118→
119→    bIsInRound = false;
120→
121→    SetPhase(EBattlePhase::BP_RoundEnd);
122→
123→    // 通知玩家本回合结束
124→    for (FConstPlayerControllerIterator It = GetWorld()->GetPlayerControllerIterator(); It; ++It)
125→    {
126→        if (ALFPTacticsPlayerController* PC = Cast<ALFPTacticsPlayerController>(*It))
127→        {
128→            PC->OnRoundEnded(CurrentRound);
129→        }
130→    }
131→
132→    // 添加延迟后开始新回合
133→    FTimerHandle TimerHandle;
134→    GetWorld()->GetTimerManager().SetTimer(TimerHandle, this, &ALFPTurnManager::BeginNewRound, 0.5f, false);
135→}
