195→void ALFPTurnManager::ProcessNextEnemyPlan()
196→{
197→    if (CurrentPlanningEnemyIndex >= PlanningOrderEnemies.Num())
198→    {
199→        // 所有敌人规划完毕
200→        EndEnemyPlanningPhase();
201→        return;
202→    }
203→
204→    ALFPTacticsUnit* Enemy = PlanningOrderEnemies[CurrentPlanningEnemyIndex];
205→
206→    // 跳过死亡单位
207→    if (!Enemy || !Enemy->IsAlive())
208→    {
209→        CurrentPlanningEnemyIndex++;
210→        ProcessNextEnemyPlan();
211→        return;
212→    }
213→
214→    ALFPAIController* AIController = Enemy->GetAIController();
215→    if (!AIController)
216→    {
217→        CurrentPlanningEnemyIndex++;
218→        ProcessNextEnemyPlan();
219→        return;
220→    }
221→
222→    // 移动前等待，让玩家观察当前局势
223→    FTimerHandle TimerHandle;
224→    GetWorld()->GetTimerManager().SetTimer(
225→        TimerHandle,
226→        this,
227→        &ALFPTurnManager::ExecuteCurrentEnemyPlan,
228→        EnemyPlanPreMoveDelay,
229→        false
230→    );
231→}
232→
233→void ALFPTurnManager::ExecuteCurrentEnemyPlan()
234→{
235→    if (CurrentPlanningEnemyIndex >= PlanningOrderEnemies.Num())
236→    {
237→        EndEnemyPlanningPhase();
238→        return;
239→    }
240→
241→    ALFPTacticsUnit* Enemy = PlanningOrderEnemies[CurrentPlanningEnemyIndex];
242→    if (!Enemy || !Enemy->IsAlive())
243→    {
244→        CurrentPlanningEnemyIndex++;
245→        ProcessNextEnemyPlan();
246→        return;
247→    }
248→
249→    ALFPAIController* AIController = Enemy->GetAIController();
250→    if (!AIController)
251→    {
252→        CurrentPlanningEnemyIndex++;
253→        ProcessNextEnemyPlan();
254→        return;
255→    }
256→
257→    // 创建行动计划，传入预分配的技能
258→    ULFPSkillBase* PreAllocatedSkill = nullptr;
259→    if (ULFPSkillBase** Found = AllocatedSkills.Find(Enemy))
260→    {
261→        PreAllocatedSkill = *Found;
262→    }
263→    FEnemyActionPlan Plan = AIController->CreateActionPlan(PreAllocatedSkill);
264→
265→    // 存储计划
266→    EnemyActionPlans.Add(Plan);
267→    Enemy->SetActionPlan(Plan);
268→
269→    // 推进到下一个敌人
270→    CurrentPlanningEnemyIndex++;
271→
272→    // 如果敌人正在移动，等移动完成后再推进
273→    if (Enemy->bIsMoving)
274→    {
275→        // 记录当前移动中的敌人，回调中需要解绑
276→        PlanningMovingEnemy = Enemy;
277→        Enemy->OnMoveFinished.AddDynamic(this, &ALFPTurnManager::OnEnemyPlanMoveComplete);
278→    }
279→    else
280→    {
281→        // 没有移动，直接推进下一个敌人
282→        ProcessNextEnemyPlan();
283→    }
284→}
285→
286→void ALFPTurnManager::OnEnemyPlanMoveComplete()
287→{
288→    // 解绑委托
289→    if (PlanningMovingEnemy)
290→    {
291→        PlanningMovingEnemy->OnMoveFinished.RemoveDynamic(this, &ALFPTurnManager::OnEnemyPlanMoveComplete);
292→        PlanningMovingEnemy = nullptr;
293→    }
294→
295→    // 移动完成后推进下一个敌人规划
296→    FTimerHandle TimerHandle;
297→    GetWorld()->GetTimerManager().SetTimer(
298→        TimerHandle,
299→        this,
300→        &ALFPTurnManager::ProcessNextEnemyPlan,
301→        EnemyPlanPostMoveDelay,
302→        false
303→    );
304→}
