342→        Unit->OnTurnStarted();
343→
344→        ExecuteEnemyPlan(Unit);
345→        return;
346→    }
347→
348→    // 玩家单位：保持原有逻辑
349→    if (Unit)
350→    {
351→        Unit->OnTurnStarted();
352→    }
353→
354→    if (PC)
