362→void ALFPTurnManager::ExecuteEnemyPlan(ALFPTacticsUnit* Unit)
363→{
364→    const FEnemyActionPlan& Plan = GetPlanForEnemy(Unit);
365→
366→    if (Plan.bIsValid && Plan.PlannedSkill)
367→    {
368→        // 在原定目标格子释放技能（即使目标已死亡）
369→        // AP 已在规划阶段 AllocateEnemySkills 中扣除
370→        Unit->ExecuteSkill(Plan.PlannedSkill, Plan.TargetTile);
371→    }
372→
373→    // 清除头顶技能图标
374→    Unit->ClearActionPlan();
375→
376→    // 短延时后结束回合（让玩家看到技能效果）
377→    FTimerHandle TimerHandle;
378→    GetWorld()->GetTimerManager().SetTimer(TimerHandle, [this, Unit]()
379→    {
