399→void ALFPTurnManager::PassTurn()
400→{
401→    if (bBattleEnded) return;
402→
403→    if (TurnOrderUnits.IsEmpty())
404→    {
405→        return;
406→    }
407→
408→    // 结束当前单位回合
409→    if (CurrentUnit)
410→    {
411→        EndUnitTurn(CurrentUnit);
412→    }
413→
414→    // 找到下一个未行动的单位
415→    int32 CurrentIndex = CurrentUnit ? TurnOrderUnits.Find(CurrentUnit) : -1;
416→    int32 StartIndex = (CurrentIndex + 1) % TurnOrderUnits.Num();
417→
418→    // 检查所有单位是否行动完毕
419→    bool TurnOrderUnitsActed = true;
420→    for (ALFPTacticsUnit* Unit : TurnOrderUnits)
421→    {
422→        if (Unit && Unit->IsAlive() && !Unit->HasActed())
423→        {
424→            TurnOrderUnitsActed = false;
425→            break;
426→        }
427→    }
428→
429→    if (TurnOrderUnitsActed)
430→    {
431→        // 所有单位行动完毕，结束回合
432→        EndCurrentRound();
433→    }
434→    else
435→    {
436→        // 寻找下一个未行动单位
437→        for (int32 i = 0; i < TurnOrderUnits.Num(); i++)
438→        {
439→            int32 Index = (StartIndex + i) % TurnOrderUnits.Num();
440→            ALFPTacticsUnit* NextUnit = TurnOrderUnits[Index];
441→
442→            if (NextUnit && NextUnit->IsAlive() && !NextUnit->HasActed())
443→            {
444→                BeginUnitTurn(NextUnit);
445→                return;
446→            }
447→        }
448→
449→        // 没有找到未行动单位，结束回合
450→        EndCurrentRound();
451→    }
452→}
