532→
533→void ALFPTurnManager::AllocateEnemySkills()
534→{
535→    AllocatedSkills.Empty();
536→
537→    // 收集所有敌方单位的所有消耗AP的技能候选
538→    struct FSkillCandidate
539→    {
540→        ALFPTacticsUnit* Unit;
541→        ULFPSkillBase* Skill;
542→        float EffectivePriority;
543→    };
544→    TArray<FSkillCandidate> Candidates;
545→
546→    for (ALFPTacticsUnit* Enemy : PlanningOrderEnemies)
547→    {
548→        if (!Enemy || !Enemy->IsAlive()) continue;
549→
550→        TArray<ULFPSkillBase*> Skills = Enemy->GetAvailableSkills();
551→        for (ULFPSkillBase* Skill : Skills)
552→        {
553→            if (!Skill) continue;
554→            if (Skill->ActionPointCost <= 0) continue; // 0消耗技能不参与竞争
555→            if (Skill->CurrentCooldown > 0) continue;  // 冷却中跳过
556→
557→            FSkillCandidate Candidate;
558→            Candidate.Unit = Enemy;
559→            Candidate.Skill = Skill;
560→            Candidate.EffectivePriority = Skill->GetEffectivePriority();
561→            Candidates.Add(Candidate);
562→        }
563→    }
564→
565→    // 按有效优先级降序排序
566→    Candidates.Sort([](const FSkillCandidate& A, const FSkillCandidate& B) {
567→        return A.EffectivePriority > B.EffectivePriority;
568→    });
569→
570→    // 依次分配：如果阵营AP足够且该单位尚未分配
571→    for (const FSkillCandidate& Candidate : Candidates)
572→    {
573→        // 该单位已分配过技能，跳过
574→        if (AllocatedSkills.Contains(Candidate.Unit)) continue;
575→
576→        // 检查阵营AP是否足够
577→        if (HasEnoughFactionAP(EUnitAffiliation::UA_Enemy, Candidate.Skill->ActionPointCost))
578→        {
579→            AllocatedSkills.Add(Candidate.Unit, Candidate.Skill);
580→            ConsumeFactionAP(EUnitAffiliation::UA_Enemy, Candidate.Skill->ActionPointCost);
581→        }
582→    }
583→
584→    // 未分配到AP技能的敌人会在 CreateActionPlan 中 fallback 到默认攻击
585→}
