140→
141→    // 距离系数（越近仇恨越高）
142→    int32 Dist = FLFPHexCoordinates::Distance(
143→        Caster->GetCurrentCoordinates(),
144→        Target->GetCurrentCoordinates()
145→    );
146→    float DistanceFactor = 1.0f / FMath::Max(Dist, 1);
147→
148→    return Hatred * DistanceFactor;
149→}
