 63→void ULFPDeploymentWidget::MarkUnitPlaced(int32 PartyIndex, bool bPlaced)
 64→{
 65→	if (!PlacedStates.IsValidIndex(PartyIndex)) return;
 66→
 67→	PlacedStates[PartyIndex] = bPlaced;
 68→	UpdateSlotVisual(PartyIndex);
 69→
 70→	// 检查是否全部放置完毕
 71→	bool bAllPlaced = true;
 72→	for (int32 i = 0; i < CachedPartyUnits.Num() && i < PlacedStates.Num(); i++)
 73→	{
 74→		if (CachedPartyUnits[i].IsValid() && !PlacedStates[i])
 75→		{
 76→			bAllPlaced = false;
 77→			break;
 78→		}
 79→	}
 80→	SetConfirmEnabled(bAllPlaced);
 81→}
