 97→void ULFPDeploymentWidget::UpdateSlotVisual(int32 Index)
 98→{
 99→	UImage* Img = GetUnitImage(Index);
100→	UButton* Btn = GetUnitButton(Index);
101→
102→	bool bPlaced = PlacedStates.IsValidIndex(Index) && PlacedStates[Index];
103→
104→	// 已放置：禁用按钮，防止重复生成
105→	if (Btn)
106→	{
107→		Btn->SetIsEnabled(!bPlaced);
108→	}
109→
110→	if (Img)
111→	{
112→		if (bPlaced)
113→		{
114→			// 已放置：半透明
115→			Img->SetColorAndOpacity(FLinearColor(0.5f, 0.5f, 0.5f, 0.5f));
116→		}
117→		else
118→		{
119→			// 未放置：正常
120→			Img->SetColorAndOpacity(FLinearColor::White);
121→		}
122→	}
123→}
