211→void ULFPSkillButtonWidget::UpdateCooldownDisplay()
212→{
213→    if (!CooldownText || !AssociatedSkill) return;
214→
215→    if (AssociatedSkill->CurrentCooldown > 0)
216→    {
217→        // 显示冷却信息
218→        FString CooldownString = FString::Printf(TEXT("%d"), AssociatedSkill->CurrentCooldown);
219→        CooldownText->SetText(FText::FromString(CooldownString));
220→        CooldownText->SetVisibility(ESlateVisibility::HitTestInvisible);
221→        CooldownText->SetColorAndOpacity(CooldownTextColor);
222→    }
223→    else if (AssociatedSkill->CooldownRounds > 0)
224→    {
225→        // 显示冷却回合数（当前不在冷却中）
226→        FString CooldownString = FString::Printf(TEXT("%dR"), AssociatedSkill->CooldownRounds);
227→        CooldownText->SetText(FText::FromString(CooldownString));
228→        CooldownText->SetVisibility(ESlateVisibility::HitTestInvisible);
229→        CooldownText->SetColorAndOpacity(AvailableTextColor);
230→    }
231→    else
232→    {
233→        // 无冷却，隐藏冷却文本
234→        CooldownText->SetVisibility(ESlateVisibility::Collapsed);
235→    }
236→}
